export interface Unit {
  id: number;
  name: string;
  max_guests: number;
  pricing_model: 'per_unit' | 'per_person';
  price: number;
  available_count: number;
  pictures: string[];
}

export interface Property {
  id: number;
  name: string;
  currency: string;
  tax_rate: number;
  pictures: string[];
}

export interface PropertyData {
  property: Property;
  units: Unit[];
}

export type BookingStatus = 'pending' | 'confirmed' | 'failed';

export interface BookingStatusResponse {
  status: BookingStatus;
  confirmation_id: string | null;
  message: string | null;
}

import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export interface RoomSelection {
  unitId: number;
  quantity: number;
  guests: number;
}

interface BookingState {
  currentStep: number;
  checkIn: string | null;
  checkOut: string | null;
  rooms: RoomSelection[];
  specialRequests: string;
  bookingId: number | null;
}

interface BookingActions {
  setDates: (checkIn: string, checkOut: string) => void;
  setRooms: (rooms: RoomSelection[]) => void;
  setSpecialRequests: (requests: string) => void;
  setBookingId: (id: number) => void;
  nextStep: () => void;
  prevStep: () => void;
  goToStep: (step: number) => void;
  reset: () => void;
}

const initialState: BookingState = {
  currentStep: 1,
  checkIn: null,
  checkOut: null,
  rooms: [],
  specialRequests: '',
  bookingId: null,
};

export const useBookingStore = create<BookingState & BookingActions>()(
  persist(
    (set) => ({
      ...initialState,
      setDates: (checkIn, checkOut) => set({ checkIn, checkOut }),
      setRooms: (rooms) => set({ rooms }),
      setSpecialRequests: (specialRequests) => set({ specialRequests }),
      setBookingId: (bookingId) => set({ bookingId }),
      nextStep: () => set((state) => ({ currentStep: Math.min(state.currentStep + 1, 5) })),
      prevStep: () => set((state) => ({ currentStep: Math.max(state.currentStep - 1, 1) })),
      goToStep: (step) => set({ currentStep: step }),
      reset: () => set(initialState),
    }),
    { name: 'booking-wizard' }
  )
);

import { z } from 'zod';

export const dateSchema = z
  .object({
    checkIn: z
      .string()
      .min(1, 'Check-in date is required')
      .refine((val) => {
        const date = new Date(val);
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        return date >= today;
      }, 'Check-in must be today or later'),
    checkOut: z.string().min(1, 'Check-out date is required'),
  })
  .refine(
    (data) => {
      if (!data.checkIn || !data.checkOut) return true;
      return new Date(data.checkOut) > new Date(data.checkIn);
    },
    { message: 'Check-out must be after check-in', path: ['checkOut'] }
  );

export type DateFormValues = z.infer<typeof dateSchema>;

import { z } from 'zod';

export const roomSelectionSchema = z.object({
  unitId: z.number(),
  quantity: z.number().int().min(0),
  guests: z.number().int().min(0),
});

export const roomSchema = z.object({
  rooms: z
    .array(roomSelectionSchema)
    .refine((rooms) => rooms.some((r) => r.quantity > 0), {
      message: 'Please select at least one room',
    }),
});

export type RoomFormValues = z.infer<typeof roomSchema>;

import { z } from 'zod';
import { dateSchema } from './dateSchema';
import { roomSelectionSchema } from './roomSchema';

export const bookingSchema = dateSchema.innerType().extend({
  rooms: z
    .array(roomSelectionSchema)
    .refine((rooms) => rooms.some((r) => r.quantity > 0), {
      message: 'Please select at least one room',
    }),
  specialRequests: z.string().max(500, 'Special requests must be 500 characters or less').optional(),
});

export type BookingFormValues = z.infer<typeof bookingSchema>;

export { dateSchema, type DateFormValues } from './dateSchema';
export { roomSchema, roomSelectionSchema, type RoomFormValues } from './roomSchema';
export { bookingSchema, type BookingFormValues } from './bookingSchema';

const currencyFormatter = new Intl.NumberFormat('en-ZA', {
  style: 'currency',
  currency: 'ZAR',
});

export function formatCurrency(amount: number): string {
  return currencyFormatter.format(amount);
}

import type { Unit } from '@/types/property';
import type { RoomSelection } from '@/Stores/useBookingStore';

export interface PriceLineItem {
  unitName: string;
  unitPrice: number;
  pricingModel: 'per_unit' | 'per_person';
  quantity: number;
  guests: number;
  nights: number;
  lineTotal: number;
}

export interface PriceBreakdown {
  lineItems: PriceLineItem[];
  subtotal: number;
  taxRate: number;
  taxAmount: number;
  total: number;
}

export function calculateNights(checkIn: string, checkOut: string): number {
  const start = new Date(checkIn);
  const end = new Date(checkOut);
  const diffMs = end.getTime() - start.getTime();
  return Math.max(Math.round(diffMs / (1000 * 60 * 60 * 24)), 0);
}

export function calculatePrice(
  rooms: RoomSelection[],
  units: Unit[],
  nights: number,
  taxRate: number
): PriceBreakdown {
  const unitMap = new Map(units.map((u) => [u.id, u]));

  const lineItems: PriceLineItem[] = rooms
    .filter((r) => r.quantity > 0)
    .map((room) => {
      const unit = unitMap.get(room.unitId);
      if (!unit) {
        return null;
      }

      const lineTotal =
        unit.pricing_model === 'per_unit'
          ? unit.price * nights * room.quantity
          : unit.price * room.guests * nights * room.quantity;

      return {
        unitName: unit.name,
        unitPrice: unit.price,
        pricingModel: unit.pricing_model,
        quantity: room.quantity,
        guests: room.guests,
        nights,
        lineTotal,
      };
    })
    .filter((item): item is PriceLineItem => item !== null);

  const subtotal = lineItems.reduce((sum, item) => sum + item.lineTotal, 0);
  const taxAmount = subtotal * taxRate;
  const total = subtotal + taxAmount;

  return { lineItems, subtotal, taxRate, taxAmount, total };
}

import { useState, useEffect, useRef, useCallback } from 'react';
import axios from 'axios';
import type { BookingStatus, BookingStatusResponse } from '@/types/booking';

const POLL_INTERVAL_MS = 2500;
const TIMEOUT_MS = 60000;

interface UseBookingStatusResult {
  status: BookingStatus | null;
  confirmationId: string | null;
  isPolling: boolean;
}

export function useBookingStatus(bookingId: number | null): UseBookingStatusResult {
  const [status, setStatus] = useState<BookingStatus | null>(null);
  const [confirmationId, setConfirmationId] = useState<string | null>(null);
  const [isPolling, setIsPolling] = useState(false);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const stopPolling = useCallback(() => {
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
      timeoutRef.current = null;
    }
    setIsPolling(false);
  }, []);

  useEffect(() => {
    if (!bookingId) return;

    setIsPolling(true);
    setStatus('pending');

    const poll = async () => {
      try {
        const { data } = await axios.get<BookingStatusResponse>(
          `/api/bookings/${bookingId}/status`
        );
        setStatus(data.status);
        if (data.confirmation_id) {
          setConfirmationId(data.confirmation_id);
        }
        if (data.status === 'confirmed' || data.status === 'failed') {
          stopPolling();
        }
      } catch {
        // Keep polling on network errors - the server might be temporarily unavailable
      }
    };

    // Poll immediately, then on interval
    poll();
    intervalRef.current = setInterval(poll, POLL_INTERVAL_MS);

    // Safety timeout to prevent infinite polling
    timeoutRef.current = setTimeout(() => {
      stopPolling();
      setStatus('failed');
    }, TIMEOUT_MS);

    return stopPolling;
  }, [bookingId, stopPolling]);

  return { status, confirmationId, isPolling };
}

import { useRef, useEffect } from 'react';
import { cn } from '@/lib/utils';
import { useBookingStore } from '@/Stores/useBookingStore';
import { DateStep } from './DateStep';
import { RoomStep } from './RoomStep';
import { SummaryStep } from './SummaryStep';
import { StatusStep } from './StatusStep';
import type { PropertyData } from '@/types/property';
import type { User } from '@/types';

interface BookingWizardProps {
  propertyData: PropertyData;
  auth: { user: User | null };
}

const STEPS = [
  { number: 1, label: 'Dates' },
  { number: 2, label: 'Rooms' },
  { number: 3, label: 'Summary' },
  { number: 5, label: 'Status' },
] as const;

export function BookingWizard({ propertyData, auth }: BookingWizardProps) {
  const currentStep = useBookingStore((s) => s.currentStep);
  const stepContainerRef = useRef<HTMLDivElement>(null);

  // Focus management on step change
  useEffect(() => {
    stepContainerRef.current?.focus();
  }, [currentStep]);

  return (
    <div className={cn('mx-auto w-full max-w-3xl space-y-8')}>
      {/* Step indicator */}
      <nav aria-label="Booking progress">
        <ol className={cn('flex items-center justify-center gap-2 sm:gap-4')}>
          {STEPS.map(({ number, label }) => {
            const isActive = currentStep === number;
            const isCompleted = currentStep > number;
            // Status step is only reached via booking submission
            const isReachable = number < 5 || currentStep === 5;

            return (
              <li key={number} className={cn('flex items-center gap-2')}>
                <div
                  className={cn(
                    'flex h-8 w-8 items-center justify-center rounded-full text-sm font-medium transition-colors',
                    isActive && 'bg-primary text-primary-foreground',
                    isCompleted && 'bg-primary/20 text-primary',
                    !isActive && !isCompleted && 'bg-muted text-muted-foreground'
                  )}
                  aria-current={isActive ? 'step' : undefined}
                  aria-label={`Step ${number}: ${label}${isCompleted ? ' (completed)' : ''}${isActive ? ' (current)' : ''}`}
                >
                  {isCompleted ? (
                    <svg className={cn('h-4 w-4')} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                    </svg>
                  ) : (
                    number === 5 ? 4 : number
                  )}
                </div>
                <span
                  className={cn(
                    'hidden text-sm sm:inline',
                    isActive ? 'font-medium text-foreground' : 'text-muted-foreground',
                    !isReachable && 'opacity-50'
                  )}
                >
                  {label}
                </span>
                {number !== 5 && (
                  <div
                    className={cn(
                      'hidden h-px w-8 sm:block',
                      isCompleted ? 'bg-primary' : 'bg-border'
                    )}
                    aria-hidden="true"
                  />
                )}
              </li>
            );
          })}
        </ol>
      </nav>

      {/* Step content */}
      <div
        ref={stepContainerRef}
        tabIndex={-1}
        className={cn('outline-none')}
        aria-live="polite"
      >
        {currentStep === 1 && <DateStep />}
        {currentStep === 2 && <RoomStep propertyData={propertyData} />}
        {currentStep === 3 && <SummaryStep propertyData={propertyData} auth={auth} />}
        {currentStep === 5 && <StatusStep propertyData={propertyData} />}
      </div>
    </div>
  );
}

